import React, { useState, useRef, useEffect } from 'react';
import { 
  ChevronLeft, 
  Check, 
  Star, 
  Plus, 
  Trash2,
  X
} from 'lucide-react';
import TodoStep from './TodoStep';

const TodoDetails = ({ 
  selectedTodo, 
  onBack, 
  onToggleComplete, 
  onToggleStarred, 
  onDelete,
  showNewStep,
  setShowNewStep,
  newStepText,
  setNewStepText,
  onAddStep,
  onToggleStepComplete,
  onDeleteStep,
  notes,
  setNotes,
  onUpdateTodoDescription
}) => {
  const [isEditingTitle, setIsEditingTitle] = useState(false);
  const [editedTitle, setEditedTitle] = useState('');
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const titleInputRef = useRef(null);

  useEffect(() => {
    if (isEditingTitle && titleInputRef.current) {
      titleInputRef.current.focus();
      titleInputRef.current.select();
    }
  }, [isEditingTitle]);

  const handleTitleClick = () => {
    setIsEditingTitle(true);
    setEditedTitle(selectedTodo.description);
  };

  const handleTitleSave = () => {
    if (editedTitle.trim() && editedTitle !== selectedTodo.description) {
      onUpdateTodoDescription(selectedTodo.id, editedTitle.trim());
    }
    setIsEditingTitle(false);
  };

  const handleTitleCancel = () => {
    setIsEditingTitle(false);
    setEditedTitle('');
  };

  const handleTitleKeyDown = (e) => {
    if (e.key === 'Enter') {
      handleTitleSave();
    } else if (e.key === 'Escape') {
      handleTitleCancel();
    }
  };

  const handleTitleBlur = () => {
    handleTitleSave();
  };

  const handleDeleteClick = () => {
    setShowDeleteModal(true);
  };

  const handleConfirmDelete = () => {
    onDelete(selectedTodo.id);
    setShowDeleteModal(false);
    onBack();
  };

  const handleCancelDelete = () => {
    setShowDeleteModal(false);
  };
  const handleStepKeyPress = (e) => {
    if (e.key === 'Enter') {
      onAddStep();
      setShowNewStep(true); // Keep showing for next step
    }
  };

  const handleStepBlur = () => {
    if (newStepText.trim()) {
      onAddStep();
    }
    setShowNewStep(false);
  };

  return (
    <>
      <div className="p-6 flex-1">
        {/* Header */}
        <div className="flex items-center gap-3 mb-6">
          <button
            onClick={onBack}
            className="text-neutral-400 hover:text-white transition-colors"
          >
            <ChevronLeft className="w-5 h-5" />
          </button>
          <h3 className="text-white text-lg font-semibold">Todo Details</h3>
        </div>

        {/* Todo main info */}
        <div className="flex items-center gap-3 mb-4">
          <button
            onClick={() => onToggleComplete(selectedTodo.id)}
            className={`w-6 h-6 rounded border-2 flex items-center justify-center transition-colors ${
              selectedTodo.completed 
                ? 'bg-green-500 border-green-500' 
                : 'border-neutral-400 hover:border-white'
            }`}
          >
            {selectedTodo.completed && <Check className="w-4 h-4 text-white" />}
          </button>

          <span className={`text-white flex-1 ${selectedTodo.completed ? 'line-through opacity-60' : ''}`}>
            {selectedTodo.description}
          </span>

          <button
            onClick={() => onToggleStarred(selectedTodo.id)}
            className={`transition-colors ${
              selectedTodo.starred 
                ? 'text-yellow-500' 
                : 'text-neutral-400 hover:text-yellow-500'
            }`}
          >
            <Star className={`w-5 h-5 ${selectedTodo.starred ? 'fill-current' : ''}`} />
          </button>
        </div>

        {/* Add step button */}
        <button
          onClick={() => setShowNewStep(true)}
          className="w-full flex items-center gap-2 p-3 border border-neutral-600 rounded-lg text-neutral-400 hover:text-white hover:border-neutral-500 transition-colors mb-4"
        >
          <Plus className="w-4 h-4" />
          <span>Add a step</span>
        </button>

        {/* Steps */}
        <div className="space-y-2 mb-6">
          {selectedTodo.steps.map(step => (
            <TodoStep
              key={step.id}
              step={step}
              onToggleComplete={onToggleStepComplete}
              onDelete={onDeleteStep}
            />
          ))}

          {showNewStep && (
            <div className="flex items-center gap-3 p-2">
              <div className="w-4 h-4 rounded border-2 border-neutral-400"></div>
              <input
                type="text"
                placeholder="Step description..."
                value={newStepText}
                onChange={(e) => setNewStepText(e.target.value)}
                onKeyPress={handleStepKeyPress}
                onBlur={handleStepBlur}
                autoFocus
                className="flex-1 bg-transparent text-white placeholder-neutral-400 focus:outline-none"
              />
            </div>
          )}
        </div>

        {/* Action buttons */}
                  <div className="space-y-3 mb-6">
                    <button className="w-full p-3 border border-neutral-600 rounded-lg text-white hover:bg-neutral-700 transition-colors">
                      Remind me
                    </button>
                    <button className="w-full p-3 border border-neutral-600 rounded-lg text-white hover:bg-neutral-700 transition-colors">
                      Set time
                    </button>
                    <button className="w-full p-3 border border-neutral-600 rounded-lg text-white hover:bg-neutral-700 transition-colors">
                      Repeat
                    </button>
                  </div>

                  {/* Notes */}
                  <div>
                    <label className="block text-white text-sm font-medium mb-2">Notes</label>
                    <textarea
                      value={notes}
                      onChange={(e) => setNotes(e.target.value)}
                      placeholder="Add notes..."
                      className="w-full border border-neutral-500 rounded-lg p-3 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent resize-none bg-transparent"
                      rows="4"
                      style={{ minHeight: '100px' }}
                    />
                  </div>
      </div>

      {/* Footer */}
      <div className="border-t border-neutral-700 p-4 flex items-center justify-between">
        <span className="text-neutral-400 text-sm">Created {selectedTodo.createdAt}</span>
        <button
          onClick={() => onDelete(selectedTodo.id)}
          className="text-neutral-500 hover:text-red-500 transition-colors"
        >
          <Trash2 className="w-4 h-4" />
        </button>
      </div>
    </>
  );
};

export default TodoDetails;
